var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"혀, 형님! 습격입니다! 우리 애들이 손도 못 쓰고 있습니다!","JPN":"あ、兄貴！　襲撃です！　到底手に負えない状態です！","ENG":"Sir! It's an ambush! Our boys are helpless!","TWN":"大、大哥！有人偷襲！我們抵擋不住！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"......그러니까 불법 무기를 유통하다 어떤 여자한테 다 죽게 생겨서 경비대에 신고하셨다고요?","JPN":"……つまり、違法武器を流通していたらある女性に殺されそうになって、警備隊に通報したのですか？","ENG":"... So you called this in because some lady almost killed all of you while you were illegally selling weapons?","TWN":"……你是說，流通非法武器的時候差點死在一個女人的手上，所以跟警備隊報警了是嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"제프네가 당했어? ......뭐? 메이드가 뭐 어째?","JPN":"ジェフたちがやられた？　……はあ？　メイドがなんだって？","ENG":"Someone took down Jeff's gang? What? A maid?","TWN":"傑夫內被偷襲？……什麼？女僕？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OFFICER_EXTRA_MALE_NULL","text":{"KOREA":"저, 정말 시세보다 싸게 파는 거 맞죠?","JPN":"あの、本当に相場より安く売っているんですよね？","ENG":"I-is this really under the market price?","TWN":"這、這價格真的低於市面價？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"어허, 왜 이래. 우리도 밑지는 장사야.","JPN":"おいおい、なんてこと聞くんだ。この値段だと元も取れないぞ。","ENG":"Come on, we barely make any profit off of this.","TWN":"呵呵，我們也掙不到錢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"서비스로 주는 이 권총만 해도 얼만지 알아?","JPN":"オマケのこの拳銃だけでもいくらするか知ってんのか？","ENG":"You have any idea how much this complementary pistol costs?","TWN":"就這個免費送你的槍，你知道值多少錢嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OFFICER_EXTRA_MALE_NULL","text":{"KOREA":"그, 그렇지만 전 위조 통행증 같은 게 아니라 무기만 있으면 될 거 같아서......","JPN":"で、でも私は偽通行証じゃなくて武器さえあればいいかなと思って……","ENG":"B-but all I need is a weapon... not some kind of a fake I.D....","TWN":"可、可是，我不需要偽造的通行證，我只想要武器……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"회사가 지긋지긋해서 TV에 나오는 용병들처럼 한탕 해 보고 싶다며?","JPN":"会社にはうんざりしてテレビに出てくる傭兵みたいに儲けたかったんじゃねえのか？","ENG":"Didn't you say you wanted to hit the jackpot like those mercs on TV? That you're tired of the old office life?","TWN":"你不是說厭煩了公司，所以想跟電視裡的那些傭兵一樣幹一票嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"나도 그 맘 알지. 우리도 다 원래는 이 바닥에서 새파란 신참으로 시작했으니까.","JPN":"その気持ちはわかるぞ。俺らだって元々は右も左も分からないまっさらな状態から始めたからな。","ENG":"Hey, I feel you. We all started like that at first.","TWN":"我懂你的心情，在這個圈子我們都是從新人開始的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OFFICER_EXTRA_MALE_NULL","text":{"KOREA":"힉, 히익......!","JPN":"ひ、ひい……！","ENG":"E-eeek!","TWN":"咿，咿……！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"하하. 놀랄 만한 얘기긴 해.","JPN":"ハハハ、驚いただろ。","ENG":"Hah hah, I know it can be surprising.","TWN":"哈哈，嚇到了？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"그런데 햇병아리부터 시작하려면 실전 연습이 필요하지, 실전 연습.","JPN":"しかし、ひよっこから始めるには実戦練習が必要だ。","ENG":"But you've got to gain some real combat experience if you're just getting started.","TWN":"不過想從新手開始，就要多做實戰訓練，實戰訓練。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"그래서 관리국이 통제 중인 안전한 침식지대에 들어갈 수 있는 이 통행증이 필요한 거고.","JPN":"だから管理局が統制している安全な侵食地帯に入れる、この通行証が必要になるわけさ。","ENG":"Which is why you need this pass to let you through a safer Corrupted Area under the control of the Administration.","TWN":"所以需要這個通行證，有了這個才可以進入管理局管轄的安全的侵蝕地區。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OFFICER_EXTRA_MALE_NULL","text":{"KOREA":"사, 사람이......! 사람이 환풍구로 끌려 들어가서......!","JPN":"ひ、人が……！　人が換気口に引き込まれて……！","ENG":"Y-your companions just got dragged into the vent!","TWN":"人，人……！人被拉到了通風口……！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRADER_FOX_B_NULL","text":{"KOREA":"갑자기 왜 그래? 뭐 잘못 먹었어, 형씨?","JPN":"急にどうしたんだ？　寝ぼけてんのか？","ENG":"What's wrong, brother? You high on something?","TWN":"你怎麼了？吃錯藥了？老兄？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TRADER_FOX_B_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};